        .format = .spirv,
        .entry_point = "main",
        .code = cluster_lights_compute_spirv_code[0..],
        .reflection = .{ .num_samplers = 0, .num_storage_textures = 2, .num_storage_buffers = 0, .num_uniform_buffers = 1 },
    },
    .compute_msl = .{
        .format = .msl,
        .entry_point = "guava_cluster_lights_compute_main",
        .code = cluster_lights_compute_msl_code[0..],
        .reflection = .{ .num_samplers = 0, .num_storage_textures = 2, .num_storage_buffers = 0, .num_uniform_buffers = 1 },
    },
    .threadcount_x = 64,
    .threadcount_y = 1,
    .threadcount_z = 1,
};
pub const compute_programs = [_]*const ComputeShaderProgram{
    &ssao_compute,
    &brdf_lut,
    &irradiance_convolve,
    &ssgi_compute,
    &cluster_lights,
};

pub fn findComputeProgram(name: []const u8) ?*const ComputeShaderProgram {
    inline for (compute_programs) |program| {
        if (std.mem.eql(u8, program.name, name)) {
            return program;
        }
    }
    return null;
}
